export const FOOD_CATEGORIES: string[] = [
  'Cereals and Millets',
  'Condiments and Spices',
  'Fruits',
  'Grain Legumes',
  'Green Leafy Vegetables',
  'Mushrooms',
  'Nuts and Oil Seeds',
  'Other Vegetables',
  'Roots and Tubers',
  'Sugars',
];

export function searchFoods(query: string): FoodItem[] {
  const q = query.toLowerCase().trim();
  if (!q) return IFCT_FOODS.slice(0, 30);
  return IFCT_FOODS.filter(
    (f) => f.name.toLowerCase().includes(q) || f.category.toLowerCase().includes(q)
  ).slice(0, 60);
}

export function getFoodsByCategory(cat: string): FoodItem[] {
  return IFCT_FOODS.filter((f) => f.category === cat);
}